27: const Span = struct {
28:     // Alphabet ASCII character, could be lowercase or uppercase.
29:     base: u8,
30:     // By default, it's plain alphabet character.
31:     diacritic: Diacritic = .empty,
32:     // By default, no tone is placed.
33:     tone: Tone = .level,
34: 
35:     // Create a Span with plain alphabet character, no diacritic, no tone.
36:     fn init(base: u8) Span {
37:         return Span.init_diacritic_tone(base, .empty, .level);
38:     }
39: 
40:     // Create a Span with diacritic, no tone.
41:     fn init_diacritic(base: u8, diacritic: Diacritic) Span {
42:         return Span.init_diacritic_tone(base, diacritic, .level);
43:     }
44: 
45:     fn init_diacritic_tone(base: u8, diacritic: Diacritic, tone: Tone) Span {
46:         // Only allow a-zA-Z.
47:         assert(isAlphabetic(base));
48: 
49:         // Only allow a valid Vietnamese alphabet combinations.
50:         switch (diacritic) {
51:             // All alphabet is allowed without diacritic.
52:             .empty => {},
53:             // Only a, o, e are valid with circumflex.
54:             .circumflex => switch (base) {
55:                 'A', 'E', 'O', 'a', 'e', 'o' => {},
56:                 else => unreachable,
57:             },
58:             // Only u, o are valid with horn.
59:             .horn => switch (base) {
60:                 'O', 'U', 'o', 'u' => {},
61:                 else => unreachable,
62:             },
63:             // Only a is valid with breve.
64:             .breve => switch (base) {
65:                 'A', 'a' => {},
66:                 else => unreachable,
67:             },
68:             // Only d is valid with stroke.
69:             .stroke => switch (base) {
70:                 'D', 'd' => {},
71:                 else => unreachable,
72:             },
73:         }
74: 
75:         // Only allow tone on valid Vietnamese vowels based on Vietnamese rules.
76:         switch (tone) {
77:             // All alphabet is allowed with level.
78:             .level => {},
79:             // All vowels is allowed with remaining tones.
80:             .rising, .falling, .dipping_rising, .rising_glottalized, .falling_glottalized => switch (base) {
81:                 'A', 'E', 'I', 'O', 'U', 'Y', 'a', 'e', 'i', 'o', 'u', 'y' => {},
82:                 else => unreachable,
83:             },
84:         }
85: 
86:         return .{ .base = base, .diacritic = diacritic, .tone = tone };
87:     }
88: 
89:     // Compare only base character, ignore case and other aspects.
90:     fn equals_ignore_case_diacritic_tone(self: *const Span, base: u8) bool {
91:         // Base must be alphabet letters.
92:         assert(isAlphabetic(base));
93: 
94:         return toUpper(self.base) == toUpper(base);
95:     }
96: 
97:     // Compare the span with a base character (ignore case) and diacritic, tone is ignored.
98:     fn equals_ignore_case_tone(self: *const Span, base: u8, diacritic: Diacritic) bool {
99:         // Base must be alphabet letters.
100:         assert(isAlphabetic(base));
101: 
102:         return toUpper(self.base) == toUpper(base) and self.diacritic == diacritic;
103:     }
104: 
105:     // Compare the Span base (ignore case), diacritic, tone.
106:     fn equals_ignore_case(self: *const Span, base: u8, diacritic: Diacritic, tone: Tone) bool {
107:         // Base must be alphabet letters.
108:         assert(isAlphabetic(base));
109: 
110:         return toUpper(self.base) == toUpper(base) and self.diacritic == diacritic and self.tone == tone;
111:     }
112: 
113:     // Check if the Span.base is vowel or not.
114:     fn is_vowel(self: *const Span) bool {
115:         return switch (toUpper(self.base)) {
116:             'A', 'E', 'I', 'O', 'U', 'Y' => true,
117:             else => false,
118:         };
119:     }
120: 
121:     // Check if the Span.base is consonant or not.
122:     fn is_consonant(self: *const Span) bool {
123:         return !self.is_vowel();
124:     }
125: };
